"""Key functions for memoizing decorators."""
__all__ = ('hashkey', 'methodkey', 'typedkey', 'typedmethodkey')


class _HashedTuple(tuple):
    """A tuple that ensures that hash() will be called no more than once
    per element, since cache decorators will hash the key multiple
    times on a cache miss.  See also _HashedSeq in the standard
    library functools implementation.

    """
    __hashvalue = None

    def __hash__(self, hash=tuple.__hash__):
        hv = self.__hashvalue
        if hv is None:
            hv = hash(self)
            try:
                self.__hashvalue = hv
            except AttributeError:
                pass
        return hv

    def __add__(self, other, add=tuple.__add__):
        return _HashedTuple(add(self, other))

    def __radd__(self, other, add=tuple.__add__):
        return _HashedTuple(add(other, self))

    def __getstate__(self):
        return None


_kwmark = (_HashedTuple,)


def hashkey(*args, **kwargs):
    """Return a cache key for the specified hashable arguments."""
    if kwargs:
        return _HashedTuple(args + _kwmark + tuple(sorted(kwargs.items())))
    return _HashedTuple(args)


def methodkey(self, *args, **kwargs):
    """Return a cache key for use with cached methods."""
    return hashkey(*args, **kwargs)


def typedkey(*args, **kwargs):
    """Return a typed cache key for the specified hashable arguments."""
    if kwargs:
        return _HashedTuple(
            args + tuple(type(a) for a in args)
            + _kwmark
            + tuple(sorted(kwargs.items()))
            + tuple(type(v) for _, v in sorted(kwargs.items()))
        )
    return _HashedTuple(args + tuple(type(a) for a in args))


def typedmethodkey(self, *args, **kwargs):
    """Return a typed cache key for use with cached methods."""
    return typedkey(*args, **kwargs)

"""Method decorator helpers."""
import functools
import warnings


def warn_cache_none():
    warnings.warn(
        "cache(self) returned None. Caching will be disabled.",
        DeprecationWarning,
        stacklevel=4,
    )


def _pop(d, k):
    """Safely remove and decrement a key from computing dict."""
    computing = d
    computing[k] = computing.get(k, 0) - 1
    if computing[k] <= 0:
        computing.pop(k, None)


def _unlocked(method, cache, key):
    """No lock, no condition."""
    def wrapper(self, *args, **kwargs):
        c = cache(self)
        if c is None:
            warn_cache_none()
            return method(self, *args, **kwargs)
        k = key(self, *args, **kwargs)
        try:
            return c[k]
        except KeyError:
            pass
        v = method(self, *args, **kwargs)
        try:
            c[k] = v
        except ValueError:
            pass
        return v
    wrapper.cache = cache
    wrapper.cache_key = key
    wrapper.cache_lock = None
    wrapper.cache_condition = None
    wrapper.__wrapped__ = method
    def cache_clear(self):
        c = cache(self)
        if c is not None:
            c.clear()
    wrapper.cache_clear = cache_clear
    functools.update_wrapper(wrapper, method)
    return wrapper


def _locked(method, cache, key, lock):
    """With lock, no condition."""
    def wrapper(self, *args, **kwargs):
        c = cache(self)
        if c is None:
            warn_cache_none()
            return method(self, *args, **kwargs)
        l = lock(self)
        k = key(self, *args, **kwargs)
        with l:
            try:
                return c[k]
            except KeyError:
                pass
        v = method(self, *args, **kwargs)
        try:
            with l:
                c[k] = v
        except ValueError:
            pass
        return v
    wrapper.cache = cache
    wrapper.cache_key = key
    wrapper.cache_lock = lock
    wrapper.cache_condition = None
    wrapper.__wrapped__ = method
    def cache_clear(self):
        c = cache(self)
        if c is not None:
            l = lock(self)
            with l:
                c.clear()
    wrapper.cache_clear = cache_clear
    functools.update_wrapper(wrapper, method)
    return wrapper


def _condition(method, cache, key, lock, cond):
    """With condition variable."""
    computing = {}

    def wrapper(self, *args, **kwargs):
        c = cache(self)
        if c is None:
            warn_cache_none()
            return method(self, *args, **kwargs)
        l = lock(self)
        cd = cond(self)
        k = key(self, *args, **kwargs)
        with l:
            with cd:
                cd.wait_for(lambda: k not in computing)
            try:
                return c[k]
            except KeyError:
                pass
            computing[k] = computing.get(k, 0) + 1
        try:
            v = method(self, *args, **kwargs)
        except BaseException:
            with l:
                with cd:
                    _pop(computing, k)
                    cd.notify_all()
            raise
        try:
            with l:
                c[k] = v
        except ValueError:
            pass
        with l:
            with cd:
                _pop(computing, k)
                cd.notify_all()
        return v

    wrapper.cache = cache
    wrapper.cache_key = key
    wrapper.cache_lock = lock
    wrapper.cache_condition = cond
    wrapper.__wrapped__ = method
    def cache_clear(self):
        c = cache(self)
        if c is not None:
            l = lock(self)
            with l:
                c.clear()
    wrapper.cache_clear = cache_clear
    functools.update_wrapper(wrapper, method)
    return wrapper


def _wrapper(method, cache, key, lock=None, cond=None):
    if cond is not None:
        return _condition(method, cache, key, lock, cond)
    elif lock is not None:
        return _locked(method, cache, key, lock)
    else:
        return _unlocked(method, cache, key)

"""Extensible memoizing collections and decorators."""
__all__ = (
    'Cache', 'FIFOCache', 'LFUCache', 'LRUCache', 'RRCache',
    'TLRUCache', 'TTLCache', 'cached', 'cachedmethod',
)
__version__ = '6.1.0'

import collections
import collections.abc
import functools
import heapq
import random
import time
import warnings

from . import keys
from . import _cached
from . import _cachedmethod


_CacheInfo = collections.namedtuple(
    'CacheInfo', ['hits', 'misses', 'maxsize', 'currsize'],
)


class _DefaultSize:
    __slots__ = ()

    def __getitem__(self, _):
        raise NotImplementedError()

    def __setitem__(self, _, value):
        raise NotImplementedError()

    def pop(self, _):
        raise NotImplementedError()


class Cache(collections.abc.MutableMapping):
    """Mutable mapping to serve as a simple cache or cache base class."""
    __marker = object()
    __size = _DefaultSize()

    def __init__(self, maxsize, getsizeof=None):
        self._maxsize = maxsize
        self._getsizeof = getsizeof
        self.data = {}

    def __repr__(self):
        return '%s(maxsize=%r, currsize=%r)' % (
            self.__class__.__name__, self.maxsize, self.currsize,
        )

    @staticmethod
    def getsizeof(value):
        """Return the size of a cache element's value."""
        return 1

    @property
    def maxsize(self):
        """The maximum size of the cache."""
        return self._maxsize

    @property
    def currsize(self):
        """The current size of the cache."""
        if self._getsizeof is not None:
            return sum(self._getsizeof(v) for v in self.data.values())
        return len(self.data)

    def __contains__(self, key):
        return key in self.data

    def __getitem__(self, key):
        try:
            return self.data[key]
        except KeyError:
            if type(self).__missing__ is not Cache.__missing__:
                return self.__missing__(key)
            raise

    def __missing__(self, key):
        raise KeyError(key)

    def __setitem__(self, key, value):
        size = self._getsizeof(value) if self._getsizeof else self.getsizeof(value)

        if size > self._maxsize:
            raise ValueError('value too large')

        if key in self.data:
            del self.data[key]

        # Free space if needed
        if self._getsizeof is not None:
            while sum(self._getsizeof(v) for v in self.data.values()) + size > self._maxsize:
                self.popitem()
        else:
            while len(self.data) + 1 > self._maxsize:
                self.popitem()

        self.data[key] = value

    def __delitem__(self, key):
        del self.data[key]

    def __iter__(self):
        return iter(self.data)

    def __len__(self):
        return len(self.data)

    def __eq__(self, other):
        if isinstance(other, Cache):
            return self.data == other.data
        return NotImplemented

    def get(self, key, default=None):
        try:
            return self.data[key]
        except KeyError:
            return default

    def pop(self, key, default=__marker):
        if default is self.__marker:
            return self.data.pop(key)
        return self.data.pop(key, default)

    def setdefault(self, key, default=None):
        if key in self.data:
            return self.data[key]
        self[key] = default
        return default

    def popitem(self):
        """Remove and return an arbitrary `(key, value)` pair."""
        try:
            return self.data.popitem()
        except KeyError:
            raise KeyError('%s is empty' % self.__class__.__name__) from None


class FIFOCache(Cache):
    """First In First Out (FIFO) cache implementation."""

    def __init__(self, maxsize, getsizeof=None):
        Cache.__init__(self, maxsize, getsizeof)
        self.data = collections.OrderedDict()

    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__):
        cache_setitem(self, key, value)
        # If key was already present, move it to end (update insertion order)
        self.data.move_to_end(key)

    def __delitem__(self, key, cache_delitem=Cache.__delitem__):
        cache_delitem(self, key)

    def popitem(self):
        """Remove and return the `(key, value)` pair first inserted."""
        try:
            return self.data.popitem(last=False)
        except KeyError:
            raise KeyError('%s is empty' % self.__class__.__name__) from None


class LFUCache(Cache):
    """Least Frequently Used (LFU) cache implementation."""

    class _Link:
        __slots__ = ('count', 'keys', 'next', 'prev')

        def __init__(self, count):
            self.count = count
            self.keys = []
            self.next = None
            self.prev = None

        def unlink(self):
            self.prev.next = self.next
            self.next.prev = self.prev
            self.prev = None
            self.next = None

    def __init__(self, maxsize, getsizeof=None):
        Cache.__init__(self, maxsize, getsizeof)
        self._counts = {}  # key -> _Link (the frequency bucket)
        self._head = self._Link(0)  # sentinel head of doubly-linked list
        self._tail = self._Link(0)  # sentinel tail
        self._head.next = self._tail
        self._tail.prev = self._head

    def __getitem__(self, key, cache_getitem=Cache.__getitem__):
        cache_getitem(self, key)
        self.__touch(key)
        return self.data[key]

    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__):
        cache_setitem(self, key, value)
        if key not in self._counts:
            self.__touch(key)

    def __delitem__(self, key, cache_delitem=Cache.__delitem__):
        cache_delitem(self, key)
        link = self._counts.pop(key, None)
        if link is not None:
            link.keys.remove(key)
            if not link.keys:
                link.unlink()

    def __touch(self, key):
        """Increment use count"""
        link = self._counts.get(key)
        if link is None:
            # New key: add to count 0 (after head)
            head = self._head
            if head.next is self._tail or head.next.count > 0:
                new_link = self._Link(0)
                new_link.next = head.next
                new_link.prev = head
                head.next.prev = new_link
                head.next = new_link
                new_link.keys.append(key)
                self._counts[key] = new_link
            else:
                head.next.keys.append(key)
                self._counts[key] = head.next
        else:
            # Existing key: move to higher count bucket
            count = link.count
            link.keys.remove(key)
            next_link = link.next
            if next_link is self._tail or next_link.count != count + 1:
                new_link = self._Link(count + 1)
                new_link.next = next_link
                new_link.prev = link
                link.next = new_link
                next_link.prev = new_link
                new_link.keys.append(key)
                self._counts[key] = new_link
            else:
                next_link.keys.append(key)
                self._counts[key] = next_link
            if not link.keys:
                link.unlink()

    def popitem(self):
        """Remove and return the `(key, value)` pair least frequently used."""
        try:
            link = self._head.next
            if link is self._tail:
                raise KeyError
            key = link.keys.pop(0)
            if not link.keys:
                link.unlink()
            self._counts.pop(key)
            return key, self.data.pop(key)
        except KeyError:
            raise KeyError('%s is empty' % self.__class__.__name__) from None


class LRUCache(Cache):
    """Least Recently Used (LRU) cache implementation."""

    def __init__(self, maxsize, getsizeof=None):
        Cache.__init__(self, maxsize, getsizeof)
        self.data = collections.OrderedDict()

    def __getitem__(self, key, cache_getitem=Cache.__getitem__):
        cache_getitem(self, key)
        self.data.move_to_end(key)
        return self.data[key]

    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__):
        cache_setitem(self, key, value)
        self.data.move_to_end(key)

    def __delitem__(self, key, cache_delitem=Cache.__delitem__):
        cache_delitem(self, key)

    def __touch(self, key):
        """Mark as recently used"""
        self.data.move_to_end(key)

    def popitem(self):
        """Remove and return the `(key, value)` pair least recently used."""
        try:
            return self.data.popitem(last=False)
        except KeyError:
            raise KeyError('%s is empty' % self.__class__.__name__) from None


class RRCache(Cache):
    """Random Replacement (RR) cache implementation."""

    def __init__(self, maxsize, choice=random.choice, getsizeof=None):
        Cache.__init__(self, maxsize, getsizeof)
        self._choice = choice

    @property
    def choice(self):
        """The `choice` function used by the cache."""
        return self._choice

    def popitem(self):
        """Remove and return a random `(key, value)` pair."""
        try:
            key = self._choice(list(self.data.keys()))
            return key, self.data.pop(key)
        except (KeyError, IndexError):
            raise KeyError('%s is empty' % self.__class__.__name__) from None


class _TimedCache(Cache):
    """Base class for time aware cache implementations."""

    class _Timer:

        def __init__(self, timer):
            self._timer = timer

        def __call__(self):
            return self._timer()

        def __enter__(self):
            return self._timer()

        def __exit__(self, *exc):
            pass

        def __reduce__(self):
            return (self._timer.__class__, ())

        def __getattr__(self, name):
            return getattr(self._timer, name)

    def __init__(self, maxsize, timer=time.monotonic, getsizeof=None):
        Cache.__init__(self, maxsize, getsizeof)
        self._timer = self._Timer(timer)
        self._timestamps = {}  # key -> expiry time

    def __repr__(self, cache_repr=Cache.__repr__):
        return cache_repr(self)

    def __len__(self, cache_len=Cache.__len__):
        return cache_len(self)

    @property
    def currsize(self):
        if self._getsizeof is not None:
            return sum(self._getsizeof(v) for v in self.data.values())
        return len(self.data)

    @property
    def timer(self):
        """The timer function used by the cache."""
        return self._timer

    def clear(self):
        super().clear()
        self._timestamps.clear()

    def get(self, *args, **kwargs):
        return Cache.get(self, *args, **kwargs)

    def pop(self, *args, **kwargs):
        return Cache.pop(self, *args, **kwargs)

    def setdefault(self, *args, **kwargs):
        return Cache.setdefault(self, *args, **kwargs)


class TTLCache(_TimedCache):
    """LRU Cache implementation with per-item time-to-live (TTL) value."""

    class _Link:
        __slots__ = ('key', 'expires', 'next', 'prev')

        def __init__(self, key=None, expires=None):
            self.key = key
            self.expires = expires
            self.next = None
            self.prev = None

        def __reduce__(self):
            return (TTLCache._Link, (self.key, self.expires))

        def unlink(self):
            if self.prev is not None:
                self.prev.next = self.next
            if self.next is not None:
                self.next.prev = self.prev
            self.prev = None
            self.next = None

    def __init__(self, maxsize, ttl, timer=time.monotonic, getsizeof=None):
        _TimedCache.__init__(self, maxsize, timer, getsizeof)
        self._ttl = ttl
        # Doubly-linked list ordered by expiration time (ascending)
        self._head = self._Link()  # sentinel head
        self._tail = self._Link()  # sentinel tail
        self._head.next = self._tail
        self._tail.prev = self._head
        self._links = {}  # key -> _Link

    def __contains__(self, key):
        if key in self.data:
            # Check expiration
            link = self._links[key]
            now = self._timer()
            if link.expires > now:
                return True
            self._delitem(key)
        return False

    def __getitem__(self, key, cache_getitem=Cache.__getitem__):
        cache_getitem(self, key)
        link = self._links[key]
        now = self._timer()
        if link.expires > now:
            return self.data[key]
        # Item expired
        self._delitem(key)
        raise KeyError(key)

    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__):
        now = self._timer()
        expires = now + self._ttl
        if key in self.data:
            # Remove old link
            link = self._links[key]
            link.unlink()
            del self._links[key]
        cache_setitem(self, key, value)
        self._links[key] = self._Link(key, expires)
        link = self._links[key]
        # Insert in expiration order (ascending)
        cur = self._head
        while cur.next is not self._tail and cur.next.expires <= expires:
            cur = cur.next
        link.next = cur.next
        link.prev = cur
        cur.next.prev = link
        cur.next = link

    def __delitem__(self, key, cache_delitem=Cache.__delitem__):
        cache_delitem(self, key)
        if key in self._links:
            link = self._links.pop(key)
            link.unlink()

    def __iter__(self):
        now = self._timer()
        return iter(k for k in self.data if self._links[k].expires > now)

    def __setstate__(self, state):
        self.__dict__.update(state)
        # Rebuild link pointers after unpickling
        self._head = self._Link()
        self._tail = self._Link()
        self._head.next = self._tail
        self._tail.prev = self._head
        # Sort links by expiration and rebuild chain
        links = sorted(self._timestamps.items(), key=lambda x: x[1])
        for key, expires in links:
            link = self._Link(key, expires)
            self._links[key] = link
            # Append to tail
            link.prev = self._tail.prev
            link.next = self._tail
            self._tail.prev.next = link
            self._tail.prev = link

    @property
    def ttl(self):
        """The time-to-live value of the cache's items."""
        return self._ttl

    def expire(self, time=None):
        """Remove expired items from the cache and return an iterable of the
        expired `(key, value)` pairs.

        """
        if time is None:
            time = self._timer()
        expired = []
        # Walk from head (earliest expiration) and remove expired
        cur = self._head.next
        while cur is not self._tail and cur.expires <= time:
            key = cur.key
            link = cur
            cur = cur.next  # Advance before unlinking
            link.unlink()
            self._links.pop(key, None)
            value = self.data.pop(key)
            expired.append((key, value))
        return expired

    def popitem(self):
        """Remove and return the `(key, value)` pair least recently used that
        has not already expired.

        """
        # First expire any timed-out items
        now = self._timer()
        self.expire(now)
        # Then fall back to LRU eviction
        try:
            # Find the first non-expired item (from LRU end = front of OrderedDict)
            # Since __iter__ already filters expired, check the front
            for key in self.data:
                link = self._links.get(key)
                if link and link.expires > now:
                    break
            else:
                raise KeyError
            # Remove it
            del self[key]
            return key, self.data[key]  # wait, this doesn't work because we deleted it
        except (KeyError, StopIteration):
            raise KeyError('%s is empty' % self.__class__.__name__) from None

    def __getlink(self, key):
        """Return the _Link for a key (internal)."""
        return self._links[key]

    def __ior__(self, other):
        self.update(other)
        return self


class TLRUCache(_TimedCache):
    """Time aware Least Recently Used (TLRU) cache implementation."""

    @functools.total_ordering
    class _Item:
        __slots__ = ('key', 'expires', 'removed')

        def __init__(self, key=None, expires=None):
            self.key = key
            self.expires = expires
            self.removed = False

        def __lt__(self, other):
            return self.expires < other.expires

    def __init__(self, maxsize, ttu, timer=time.monotonic, getsizeof=None):
        _TimedCache.__init__(self, maxsize, timer, getsizeof)
        self._ttu = ttu
        self._heap = []  # min-heap of _Item objects
        self._items = {}  # key -> _Item

    def __contains__(self, key):
        if key in self.data:
            self._remove_expired()
            if key in self.data:
                item = self._items.get(key)
                if item is not None and not item.removed:
                    return True
        return False

    def __getitem__(self, key, cache_getitem=Cache.__getitem__):
        cache_getitem(self, key)
        self._remove_expired()
        item = self._items.get(key)
        if item is None or item.removed:
            raise KeyError(key)
        return self.data[key]

    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__):
        now = self._timer()
        expires = self._ttu(key, value, now)
        # Remove old item if present
        if key in self._items:
            old = self._items[key]
            old.removed = True
        cache_setitem(self, key, value)
        item = self._Item(key, expires)
        self._items[key] = item
        heapq.heappush(self._heap, item)

    def __delitem__(self, key, cache_delitem=Cache.__delitem__):
        cache_delitem(self, key)
        if key in self._items:
            item = self._items.pop(key)
            item.removed = True

    def __iter__(self):
        self._remove_expired()
        return iter(self.data)

    @property
    def ttu(self):
        """The local time-to-use function used by the cache."""
        return self._ttu

    def _remove_expired(self):
        """Remove expired items from the heap (lazy cleanup)."""
        now = self._timer()
        while self._heap:
            item = self._heap[0]
            if item.removed:
                heapq.heappop(self._heap)
                continue
            if item.expires <= now:
                heapq.heappop(self._heap)
                if item.key in self._items and self._items[item.key] is item:
                    self._items.pop(item.key, None)
                    self.data.pop(item.key, None)
            else:
                break

    def expire(self, time=None):
        """Remove expired items from the cache and return an iterable of the
        expired `(key, value)` pairs.

        """
        if time is None:
            time = self._timer()
        expired = []
        self._remove_expired()
        # Also check items that are still in heap but expired
        for item in list(self._heap):
            if item.removed:
                continue
            if item.expires <= time:
                item.removed = True
                if item.key in self._items and self._items[item.key] is item:
                    self._items.pop(item.key, None)
                    value = self.data.pop(item.key, None)
                    if value is not None:
                        expired.append((item.key, value))
        self._heap = [it for it in self._heap if not it.removed]
        heapq.heapify(self._heap)
        return expired

    def popitem(self):
        """Remove and return the `(key, value)` pair least recently used that
        has not already expired.

        """
        self._remove_expired()
        # Fall back to LRU eviction (from the front of the dict, but items
        # maintain insertion order in Python 3.7+)
        try:
            # Pick a non-expired item - any item works for eviction
            for key in list(self.data.keys()):
                if key in self._items and not self._items[key].removed:
                    break
            else:
                raise KeyError
            value = self.data.pop(key)
            if key in self._items:
                item = self._items.pop(key)
                item.removed = True
            return key, value
        except KeyError:
