"""Extensible memoizing collections and decorators."""
__all__ = (
    'Cache', 'FIFOCache', 'LFUCache', 'LRUCache', 'RRCache',
    'TLRUCache', 'TTLCache', 'cached', 'cachedmethod',
)
__version__ = '6.1.0'

import collections
import collections.abc
import functools
import heapq
import random
import time
import warnings

from . import keys
from . import _cached
from . import _cachedmethod


_CacheInfo = collections.namedtuple(
    'CacheInfo', ['hits', 'misses', 'maxsize', 'currsize'],
)


class _DefaultSize:
    __slots__ = ()

    def __getitem__(self, _):
        raise NotImplementedError()

    def __setitem__(self, _, value):
        raise NotImplementedError()

    def pop(self, _):
        raise NotImplementedError()


class Cache(collections.abc.MutableMapping):
    """Mutable mapping to serve as a simple cache or cache base class."""
    __marker = object()
    __size = _DefaultSize()

    def __init__(self, maxsize, getsizeof=None):
        self._maxsize = maxsize
        self._getsizeof = getsizeof
        if getsizeof is not None:
            self.getsizeof = getsizeof
        self.data = {}

    def __repr__(self):
        return '%s(maxsize=%r, currsize=%r)' % (
            self.__class__.__name__, self.maxsize, self.currsize,
        )

    @staticmethod
    def getsizeof(value):
        """Return the size of a cache element's value."""
        return 1

    @property
    def maxsize(self):
        """The maximum size of the cache."""
        return self._maxsize

    @property
    def currsize(self):
        """The current size of the cache."""
        return sum(self.getsizeof(v) for v in self.data.values())

    def __contains__(self, key):
        return key in self.data

    def __getitem__(self, key):
        try:
            return self.data[key]
        except KeyError:
            if type(self).__missing__ is not Cache.__missing__:
                return self.__missing__(key)
            raise

    def __missing__(self, key):
        raise KeyError(key)

    def __setitem__(self, key, value):
        size = self.getsizeof(value)

        if size > self._maxsize:
            raise ValueError('value too large')

        if key in self.data:
            del self.data[key]

        while self.currsize + size > self._maxsize and self.data:
            self.popitem()

        self.data[key] = value

    def __delitem__(self, key):
        del self.data[key]

    def __iter__(self):
        return iter(self.data)

    def __len__(self):
        return len(self.data)

    def __eq__(self, other):
        if isinstance(other, Cache):
            return self.data == other.data
        return NotImplemented

    def get(self, key, default=None):
        try:
            return self.data[key]
        except KeyError:
            return default

    def pop(self, key, default=__marker):
        if default is self.__marker:
            return self.data.pop(key)
        return self.data.pop(key, default)

    def setdefault(self, key, default=None):
        if key in self.data:
            return self.data[key]
        self[key] = default
        return default

    def popitem(self):
        """Remove and return an arbitrary `(key, value)` pair."""
        try:
            return self.data.popitem()
        except KeyError:
            raise KeyError('%s is empty' % self.__class__.__name__) from None


class FIFOCache(Cache):
    """First In First Out (FIFO) cache implementation."""

    def __init__(self, maxsize, getsizeof=None):
        Cache.__init__(self, maxsize, getsizeof)
        self.data = collections.OrderedDict()

    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__):
        cache_setitem(self, key, value)
        self.data.move_to_end(key)

    def __delitem__(self, key, cache_delitem=Cache.__delitem__):
        cache_delitem(self, key)

    def popitem(self):
        """Remove and return the `(key, value)` pair first inserted."""
        try:
            return self.data.popitem(last=False)
        except KeyError:
            raise KeyError('%s is empty' % self.__class__.__name__) from None


class LFUCache(Cache):
    """Least Frequently Used (LFU) cache implementation."""

    class _Link:
        __slots__ = ('count', 'keys', 'next', 'prev')

        def __init__(self, count):
            self.count = count
            self.keys = []
            self.next = None
            self.prev = None

        def unlink(self):
            self.prev.next = self.next
            self.next.prev = self.prev
            self.prev = None
            self.next = None

    def __init__(self, maxsize, getsizeof=None):
        Cache.__init__(self, maxsize, getsizeof)
        self._freq = {}  # key -> frequency count

    def __getitem__(self, key, cache_getitem=Cache.__getitem__):
        cache_getitem(self, key)
        self.__touch(key)
        return self.data[key]

    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__):
        cache_setitem(self, key, value)
        if key not in self._freq:
            self.__touch(key)

    def __delitem__(self, key, cache_delitem=Cache.__delitem__):
        cache_delitem(self, key)
        self._freq.pop(key, None)

    def __touch(self, key):
        """Increment use count"""
        self._freq[key] = self._freq.get(key, 0) + 1

    def popitem(self):
        """Remove and return the `(key, value)` pair least frequently used."""
        if not self.data:
            raise KeyError('%s is empty' % self.__class__.__name__)
        # Find the key with minimum frequency
        min_freq = min(self._freq.values())
        for key in self.data:
            if self._freq.get(key, 0) == min_freq:
                self._freq.pop(key)
                return key, self.data.pop(key)
        # Fallback (shouldn't reach here)
        key = next(iter(self.data))
        self._freq.pop(key, None)
        return key, self.data.pop(key)


class LRUCache(Cache):
    """Least Recently Used (LRU) cache implementation."""

    def __init__(self, maxsize, getsizeof=None):
        Cache.__init__(self, maxsize, getsizeof)
        self.data = collections.OrderedDict()

    def __getitem__(self, key, cache_getitem=Cache.__getitem__):
        cache_getitem(self, key)
        self.data.move_to_end(key)
        return self.data[key]

    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__):
        cache_setitem(self, key, value)
        self.data.move_to_end(key)

    def __delitem__(self, key, cache_delitem=Cache.__delitem__):
        cache_delitem(self, key)

    def __touch(self, key):
        """Mark as recently used"""
        self.data.move_to_end(key)

    def popitem(self):
        """Remove and return the `(key, value)` pair least recently used."""
        try:
            return self.data.popitem(last=False)
        except KeyError:
            raise KeyError('%s is empty' % self.__class__.__name__) from None


class RRCache(Cache):
    """Random Replacement (RR) cache implementation."""

    def __init__(self, maxsize, choice=random.choice, getsizeof=None):
        Cache.__init__(self, maxsize, getsizeof)
        self._choice = choice

    @property
    def choice(self):
        """The `choice` function used by the cache."""
        return self._choice

    def popitem(self):
        """Remove and return a random `(key, value)` pair."""
        try:
            key = self._choice(list(self.data.keys()))
            return key, self.data.pop(key)
        except (KeyError, IndexError):
            raise KeyError('%s is empty' % self.__class__.__name__) from None


class _TimedCache(Cache):
    """Base class for time aware cache implementations."""

    class _Timer:

        def __init__(self, timer):
            self._timer = timer

        def __call__(self):
            return self._timer()

        def __enter__(self):
            return self._timer()

        def __exit__(self, *exc):
            pass

        def __reduce__(self):
            try:
                return (self._timer.__class__, ())
            except Exception:
                return (type(self), (self._timer,))

        def __getattr__(self, name):
            return getattr(self._timer, name)

    def __init__(self, maxsize, timer=time.monotonic, getsizeof=None):
        Cache.__init__(self, maxsize, getsizeof)
        self._timer = self._Timer(timer)
        self._timestamps = {}

    def __repr__(self, cache_repr=Cache.__repr__):
        return cache_repr(self)

    def __len__(self, cache_len=Cache.__len__):
        return cache_len(self)

    @property
    def currsize(self):
        return sum(self.getsizeof(v) for v in self.data.values())

    @property
    def timer(self):
        """The timer function used by the cache."""
        return self._timer

    def clear(self):
        super().clear()
        self._timestamps.clear()

    def get(self, *args, **kwargs):
        return Cache.get(self, *args, **kwargs)

    def pop(self, *args, **kwargs):
        return Cache.pop(self, *args, **kwargs)

    def setdefault(self, *args, **kwargs):
        return Cache.setdefault(self, *args, **kwargs)


class TTLCache(_TimedCache):
    """LRU Cache implementation with per-item time-to-live (TTL) value."""

    class _Link:
        __slots__ = ('key', 'expires', 'next', 'prev')

        def __init__(self, key=None, expires=None):
            self.key = key
            self.expires = expires
            self.next = None
            self.prev = None

        def __reduce__(self):
            return (TTLCache._Link, (self.key, self.expires))

        def unlink(self):
            if self.prev is not None:
                self.prev.next = self.next
            if self.next is not None:
                self.next.prev = self.prev
            self.prev = None
            self.next = None

    def __init__(self, maxsize, ttl, timer=time.monotonic, getsizeof=None):
        _TimedCache.__init__(self, maxsize, timer, getsizeof)
        self._ttl = ttl
        self._head = self._Link()
        self._tail = self._Link()
        self._head.next = self._tail
        self._tail.prev = self._head
        self._links = {}

    def __contains__(self, key):
        if key in self.data and key in self._links:
            link = self._links[key]
            now = self._timer()
            if link.expires > now:
                return True
            self._delitem(key)
        return False

    def __getitem__(self, key, cache_getitem=Cache.__getitem__):
        cache_getitem(self, key)
        if key not in self._links:
            raise KeyError(key)
        link = self._links[key]
        now = self._timer()
        if link.expires > now:
            return self.data[key]
        self._delitem(key)
        raise KeyError(key)

    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__):
        now = self._timer()
        expires = now + self._ttl
        if key in self._links:
            link = self._links[key]
            link.unlink()
            del self._links[key]
        cache_setitem(self, key, value)
        self._links[key] = self._Link(key, expires)
        link = self._links[key]
        cur = self._head
        while cur.next is not self._tail and cur.next.expires <= expires:
            cur = cur.next
        link.next = cur.next
        link.prev = cur
        cur.next.prev = link
        cur.next = link

    def __delitem__(self, key, cache_delitem=Cache.__delitem__):
        cache_delitem(self, key)
        if key in self._links:
            link = self._links.pop(key)
            link.unlink()

    def __iter__(self):
        now = self._timer()
        for k in list(self.data):
            if k in self._links and self._links[k].expires > now:
                yield k

    def __setstate__(self, state):
        self.__dict__.update(state)
        self._head = self._Link()
        self._tail = self._Link()
        self._head.next = self._tail
        self._tail.prev = self._head
        links = sorted(self._timestamps.items(), key=lambda x: x[1])
        for key, expires in links:
            link = self._Link(key, expires)
            self._links[key] = link
            link.prev = self._tail.prev
            link.next = self._tail
            self._tail.prev.next = link
            self._tail.prev = link

    @property
    def ttl(self):
