        expired `(key, value)` pairs.

        """
        if time is None:
            time = self._timer()
        expired = []
        cur = self._head.next
        while cur is not self._tail and cur.expires <= time:
            key = cur.key
            link = cur
            cur = cur.next
            link.unlink()
            if key in self._links:
                del self._links[key]
            value = self.data.pop(key, None)
            if value is not None:
                expired.append((key, value))
        return expired

    def popitem(self):
        """Remove and return the `(key, value)` pair least recently used that
        has not already expired.

        """
        now = self._timer()
        self.expire(now)
        if not self.data:
            raise KeyError('%s is empty' % self.__class__.__name__)
        # Evict LRU (first item in OrderedDict) that's not expired
        for key in list(self.data.keys()):
            if key in self._links and self._links[key].expires > now:
                value = self.data.pop(key)
                if key in self._links:
                    link = self._links.pop(key)
                    link.unlink()
                return key, value
        # If all items are expired, expire them and raise
        self.expire(now)
        raise KeyError('%s is empty' % self.__class__.__name__)

    def __getlink(self, key):
        return self._links[key]

    def __ior__(self, other):
        self.update(other)
        return self


class TLRUCache(_TimedCache):
    """Time aware Least Recently Used (TLRU) cache implementation."""

    @functools.total_ordering
    class _Item:
        __slots__ = ('key', 'expires', 'removed')

        def __init__(self, key=None, expires=None):
            self.key = key
            self.expires = expires
            self.removed = False

        def __lt__(self, other):
            return self.expires < other.expires

    def __init__(self, maxsize, ttu, timer=time.monotonic, getsizeof=None):
        _TimedCache.__init__(self, maxsize, timer, getsizeof)
        self._ttu = ttu
        self._heap = []
        self._items = {}

    def __contains__(self, key):
        self._remove_expired()
        return key in self.data

    def __getitem__(self, key, cache_getitem=Cache.__getitem__):
        self._remove_expired()
        return cache_getitem(self, key)

    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__):
        now = self._timer()
        expires = self._ttu(key, value, now)
        if key in self._items:
            old = self._items[key]
            old.removed = True
        cache_setitem(self, key, value)
        item = self._Item(key, expires)
        self._items[key] = item
        heapq.heappush(self._heap, item)

    def __delitem__(self, key, cache_delitem=Cache.__delitem__):
        self._remove_expired()
        cache_delitem(self, key)
        if key in self._items:
            item = self._items.pop(key)
            item.removed = True

    def __iter__(self):
