        return sum(self.getsizeof(v) for v in self.data.values())

    @property
    def timer(self):
        """The timer function used by the cache."""
        return self._timer

    def clear(self):
        super().clear()
        self._timestamps.clear()

    def get(self, *args, **kwargs):
        return Cache.get(self, *args, **kwargs)

    def pop(self, *args, **kwargs):
