class TTLCache(_TimedCache):
    """LRU Cache implementation with per-item time-to-live (TTL) value."""

    class _Link:
        __slots__ = ('key', 'expires', 'next', 'prev')

        def __init__(self, key=None, expires=None):
            self.key = key
            self.expires = expires
            self.next = None
            self.prev = None

        def __reduce__(self):
            return (TTLCache._Link, (self.key, self.expires))

        def unlink(self):
            if self.prev is not None:
                self.prev.next = self.next
            if self.next is not None:
                self.next.prev = self.prev
            self.prev = None
            self.next = None

    def __init__(self, maxsize, ttl, timer=time.monotonic, getsizeof=None):
        _TimedCache.__init__(self, maxsize, timer, getsizeof)
        self._ttl = ttl
        self.data = collections.OrderedDict()
        self._head = self._Link()
        self._tail = self._Link()
        self._head.next = self._tail
        self._tail.prev = self._head
        self._links = {}

    def __contains__(self, key):
        if key in self.data and key in self._links:
            link = self._links[key]
            now = self._timer()
            if link.expires > now:
                return True
            self._delitem(key)
        return False

    def __getitem__(self, key, cache_getitem=Cache.__getitem__):
        result = cache_getitem(self, key)
        if key in self._links:
            link = self._links[key]
            now = self._timer()
            if link.expires > now:
                self.data.move_to_end(key)
                return result
            self._delitem(key)
        raise KeyError(key)

    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__):
        now = self._timer()
        expires = now + self._ttl
        if key in self._links:
            link = self._links[key]
            link.unlink()
            del self._links[key]
        cache_setitem(self, key, value)
        self.data.move_to_end(key)
        self._links[key] = self._Link(key, expires)
        link = self._links[key]
        cur = self._head
        while cur.next is not self._tail and cur.next.expires <= expires:
            cur = cur.next
        link.next = cur.next
        link.prev = cur
        cur.next.prev = link
        cur.next = link

    def __delitem__(self, key, cache_delitem=Cache.__delitem__):
        cache_delitem(self, key)
        if key in self._links:
            link = self._links.pop(key)
            link.unlink()

    def __iter__(self):
        now = self._timer()
        for k in list(self.data):
            if k in self._links and self._links[k].expires > now:
                yield k

    def __setstate__(self, state):
        self.__dict__.update(state)
        self._head = self._Link()
        self._tail = self._Link()
        self._head.next = self._tail
        self._tail.prev = self._head
        links = sorted(self._timestamps.items(), key=lambda x: x[1])
        for key, expires in links:
            link = self._Link(key, expires)
            self._links[key] = link
            link.prev = self._tail.prev
            link.next = self._tail
            self._tail.prev.next = link
            self._tail.prev = link

    @property
    def ttl(self):
        """The time-to-live value of the cache's items."""
        return self._ttl

    def expire(self, time=None):
        """Remove expired items from the cache and return an iterable of the
        expired `(key, value)` pairs.

        """
        if time is None:
            time = self._timer()
        expired = []
        cur = self._head.next
        while cur is not self._tail and cur.expires <= time:
            key = cur.key
            link = cur
            cur = cur.next
            link.unlink()
            if key in self._links:
                del self._links[key]
            value = self.data.pop(key, None)
            if value is not None:
                expired.append((key, value))
        return expired

    def popitem(self):
        """Remove and return the `(key, value)` pair least recently used that
        has not already expired.

        """
        now = self._timer()
        self.expire(now)
        if not self.data:
            raise KeyError('%s is empty' % self.__class__.__name__) from None
        for key in list(self.data.keys()):
            if key in self._links and self._links[key].expires > now:
                value = self.data.pop(key)
                if key in self._links:
                    link = self._links.pop(key)
                    link.unlink()
                return key, value
        self.expire(now)
        raise KeyError('%s is empty' % self.__class__.__name__) from None

    def __getlink(self, key):
        return self._links[key]

    def __ior__(self, other):
        self.update(other)
        return self


class TLRUCache(_TimedCache):
    """Time aware Least Recently Used (TLRU) cache implementation."""

    @functools.total_ordering
    class _Item:
        __slots__ = ('key', 'expires', 'removed')

        def __init__(self, key=None, expires=None):
            self.key = key
            self.expires = expires
            self.removed = False

        def __lt__(self, other):
            return self.expires < other.expires

    def __init__(self, maxsize, ttu, timer=time.monotonic, getsizeof=None):
        _TimedCache.__init__(self, maxsize, timer, getsizeof)
        self._ttu = ttu
        self.data = collections.OrderedDict()
        self._heap = []
        self._items = {}

    def __contains__(self, key):
        self._remove_expired()
        return key in self.data

    def __getitem__(self, key, cache_getitem=Cache.__getitem__):
        self._remove_expired()
        result = cache_getitem(self, key)
        self.data.move_to_end(key)
        return result

    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__):
        now = self._timer()
        expires = self._ttu(key, value, now)
        if expires <= now:
            return
        if key in self._items:
            old = self._items[key]
            old.removed = True
        cache_setitem(self, key, value)
        self.data.move_to_end(key)
        item = self._Item(key, expires)
        self._items[key] = item
        heapq.heappush(self._heap, item)

    def __delitem__(self, key, cache_delitem=Cache.__delitem__):
        self._remove_expired()
        cache_delitem(self, key)
        if key in self._items:
            item = self._items.pop(key)
            item.removed = True

    def __iter__(self):
        self._remove_expired()
        return iter(list(self.data))

    @property
    def ttu(self):
        """The local time-to-use function used by the cache."""
        return self._ttu

    def _remove_expired(self):
        now = self._timer()
        while self._heap:
            item = self._heap[0]
            if item.removed:
                heapq.heappop(self._heap)
                continue
            if item.expires <= now:
                heapq.heappop(self._heap)
                if item.key in self._items and self._items[item.key] is item:
                    del self._items[item.key]
                    self.data.pop(item.key, None)
            else:
                break

    def expire(self, time=None):
        if time is None:
            time = self._timer()
        expired = []
        self._remove_expired()
        remaining = []
        for item in self._heap:
            if not item.removed and item.expires <= time:
                item.removed = True
                if item.key in self._items and self._items[item.key] is item:
                    del self._items[item.key]
                    value = self.data.pop(item.key, None)
                    if value is not None:
                        expired.append((item.key, value))
            else:
                remaining.append(item)
        self._heap = remaining
        heapq.heapify(self._heap)
        return expired

    def popitem(self):
        """Remove and return the `(key, value)` pair least recently used that
        has not already expired.

        """
        self._remove_expired()
        if not self.data:
            raise KeyError('%s is empty' % self.__class__.__name__) from None
        for key in list(self.data.keys()):
            value = self.data.pop(key)
            if key in self._items:
                item = self._items.pop(key)
                item.removed = True
            return key, value
        raise KeyError('%s is empty' % self.__class__.__name__) from None

    def __getitem(self, key):
        return self._items.get(key)

    def clear(self):
        super().clear()
        self._heap = []
        self._items = {}


